import { renderRoot } from "../../render";

let state = {
  messegData: [],
  newChanges: "",
};

export let addPost = () => {
  if (state.newChanges === "") {
    return;
  }
  let newPost = {
    id: 5,
    messege: state.newChanges,
    like: 23,
  };
  state.messegData.push(newPost);
  state.newChanges = "";
  renderRoot(state);
  console.log(state);
};

export let upDateChange = (newChange) => {
  state.newChanges = newChange;
  renderRoot(state);
};

export default state;
